//! Per-tile speculative-dequant op-level report on a REAL FLUX weight tile.
//!
//! Reads ONE Q8_0 weight slab from the knot (a small file-range read — does NOT
//! mmap the whole 17 GB), and:
//!   1. surveys the per-tile lattice-refinement residual distribution,
//!   2. sizes a PRINCIPLED γ from a quantile of that distribution,
//!   3. reports the op-level TILE admit rate (admitted-coarse / total) at that γ
//!      for E_8 (8-D) and Leech (24-D),
//!   4. runs the three-way forward-pass accuracy (scalar vs E_8 vs Leech output)
//!      on a fixed pseudo-random activation, vs the dequantized-Q8 reference.
//!
//! Honest: the reference is the Q8 dequant (the knot ships Q8_0), so the lattice
//! accuracy is the SECOND-ORDER shift toward the lower-second-moment continuous
//! value — stated plainly. The original-f32 superiority proof needs a ~17 GB HF
//! re-download + ~48 GB f32 render (OOMs on 16 GB) and is NOT attempted here.
//!
//! usage: flux-spec-dequant <knot> [tensor_name] [quantile]
//!   default tensor: flux_dbl_0_img_fc1_weight (12288 x 3072 Q8_0)
//!   default quantile: 0.5 (γ = 2·median residual)

use distributed_inference::flux_spec_dequant::{
    forward_accuracy_on_row, mat_vec_q8_0_spec, principled_gamma, survey_tile_residuals, Lattice,
    SpecMatmulReport,
};
use distributed_inference::loader::{fetch_knot_tensor_bytes_from_metadata, KnotWeights};
use distributed_inference::math::dequantize_q8_0_row;

const DEFAULT_TENSOR: &str = "flux_dbl_0_img_fc1_weight";

fn splitmix(state: &mut u64) -> f64 {
    *state = state.wrapping_add(0x9E37_79B9_7F4A_7C15);
    let mut z = *state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    let u = ((z ^ (z >> 31)) >> 11) as f64 / (1u64 << 53) as f64;
    (u - 0.5) * 2.0
}

#[allow(clippy::too_many_arguments)]
fn report_lattice(
    name: &str,
    lattice: Lattice,
    w: &[u8],
    n: usize,
    d: usize,
    quantile: f64,
    survey_stride: usize,
) -> (SpecMatmulReport, f64) {
    eprintln!(
        "[{name}] surveying per-tile residuals over {} rows (stride {survey_stride}) × {d} cols …",
        n.div_ceil(survey_stride)
    );
    let t0 = std::time::Instant::now();
    let (taus, mean) = survey_tile_residuals(w, n, d, lattice, survey_stride);
    eprintln!("[{name}] survey done in {:?} ({} tiles sampled)", t0.elapsed(), taus.len());
    let mut sorted = taus.clone();
    sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let p = |q: f64| {
        let idx = (((sorted.len() - 1) as f64) * q).round() as usize;
        sorted[idx.min(sorted.len() - 1)]
    };
    let gamma = principled_gamma(&sorted, quantile);

    // Run the speculative matmul on a fixed pseudo-random activation (1 token) to
    // exercise the real per-tile gating path and record the op-level admit rate.
    let mut st = 0xF10C_5EED_0000_0001u64;
    let xs: Vec<f32> = (0..d).map(|_| (splitmix(&mut st) * 0.02) as f32).collect();
    let mut out = vec![0.0f32; n];
    let mut rep = SpecMatmulReport::default();
    let tm = std::time::Instant::now();
    mat_vec_q8_0_spec(&mut out, &xs, w, n, d, 1, lattice, gamma, &mut rep);
    eprintln!("[{name}] full-matrix gated matmul in {:?}", tm.elapsed());
    rep.tau_p50 = p(0.50);
    rep.tau_p90 = p(0.90);
    rep.tau_p99 = p(0.99);
    rep.tau_max = *sorted.last().unwrap_or(&0.0);
    rep.tau_mean = mean;

    println!("=== {name} ({}D tiles) ===", lattice.dim());
    println!("  tiles: {}  admitted(coarse): {}  missed(refined): {}", rep.tiles, rep.admitted, rep.missed);
    println!(
        "  per-tile residual τ (cell units): mean {:.4}  p50 {:.4}  p90 {:.4}  p99 {:.4}  max {:.4}",
        rep.tau_mean, rep.tau_p50, rep.tau_p90, rep.tau_p99, rep.tau_max
    );
    println!(
        "  principled γ = 2·q{:.2}(τ) = {:.4}  →  OP-LEVEL ADMIT RATE = {:.2}%",
        quantile,
        gamma,
        100.0 * rep.admit_rate()
    );
    println!();
    (rep, gamma)
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        eprintln!("usage: flux-spec-dequant <knot> [tensor_name] [quantile]");
        std::process::exit(2);
    }
    let knot_path = &args[1];
    let tensor = args.get(2).map(|s| s.as_str()).unwrap_or(DEFAULT_TENSOR);
    let quantile: f64 = args.get(3).and_then(|s| s.parse().ok()).unwrap_or(0.5);
    // Survey row stride (γ-sizing sample). The full-matrix matmul ALWAYS gates
    // every row; only the residual-distribution survey is strided. Default 16.
    let survey_stride: usize = args.get(4).and_then(|s| s.parse().ok()).unwrap_or(16);

    let knot = KnotWeights::load_metadata_only(knot_path).expect("load knot metadata");
    let info = knot
        .metadata
        .get(tensor)
        .unwrap_or_else(|| panic!("tensor {tensor} not in knot metadata"))
        .clone();
    eprintln!(
        "tensor {tensor}: type={} shape={:?} length={} bytes",
        info.tensor_type, info.shape, info.length
    );
    assert!(
        info.tensor_type.eq_ignore_ascii_case("Q8_0"),
        "tensor must be Q8_0, got {}",
        info.tensor_type
    );

    let shape = info.shape.clone().expect("tensor shape");
    assert_eq!(shape.len(), 2, "expect a 2-D linear weight, got {shape:?}");
    let n = shape[0]; // rows (out features)
    let d = shape[1]; // cols (in features)

    let fetched =
        fetch_knot_tensor_bytes_from_metadata(knot_path, &knot.metadata, knot.payload_offset, tensor)
            .expect("fetch tensor bytes");
    let w = fetched.bytes;
    eprintln!("dequant block layout: {n} rows × {d} cols, {} Q8 bytes", w.len());

    println!("############################################################");
    println!("# PER-TILE SPECULATIVE DEQUANT — REAL FLUX MATMUL ({tensor})");
    println!("# {n} × {d} Q8_0   quantile q={quantile} (γ = 2·q-quantile of τ)");
    println!("############################################################");
    println!();

    use std::io::Write;
    let (_e8, _ge8) = report_lattice("E8", Lattice::E8, &w, n, d, quantile, survey_stride);
    std::io::stdout().flush().ok();
    let (_lc, _glc) = report_lattice("Leech", Lattice::Leech, &w, n, d, quantile, survey_stride);
    std::io::stdout().flush().ok();

    // ── Forward-pass accuracy on a fixed activation, single row probe set ──
    println!("=== FORWARD-PASS ACCURACY (scalar vs E8 vs Leech) ===");
    println!("  (SECOND-ORDER: reference = Q8 dequant; lattice = refined nearest point)");
    let mut st = 0xACCD_1234_5678_9ABCu64;
    let x: Vec<f32> = (0..d).map(|_| (splitmix(&mut st) * 0.02) as f32).collect();
    // Probe a spread of rows so the comparison is not a single-row fluke.
    let probe_rows = [0usize, n / 4, n / 2, (3 * n) / 4, n - 1];
    let mut row = vec![0.0f32; d];
    let mut sum_e8 = 0.0f64;
    let mut sum_leech = 0.0f64;
    let mut e8_closer = 0usize;
    for &r in &probe_rows {
        dequantize_q8_0_row(&mut row, &w, r, d);
        let acc = forward_accuracy_on_row(&row, &x, d);
        println!(
            "  row {r:>5}: ref(Q8)={:+.6}  scalar_err={:.2e}  E8_shift={:.6e}  Leech_shift={:.6e}",
            acc.ref_q8, acc.scalar_err, acc.e8_shift, acc.leech_shift
        );
        sum_e8 += acc.e8_shift;
        sum_leech += acc.leech_shift;
        if acc.leech_shift >= acc.e8_shift {
            e8_closer += 1;
        }
    }
    let nrows = probe_rows.len() as f64;
    println!();
    println!(
        "  mean output shift from Q8 reference: E8 {:.6e}   Leech {:.6e}",
        sum_e8 / nrows,
        sum_leech / nrows
    );
    println!(
        "  Leech shift ≥ E8 shift in {}/{} probe rows (Leech moves output more — \
         it lands on the lower-second-moment continuous value, per the energy win)",
        e8_closer,
        probe_rows.len()
    );
    println!();
    println!("HONEST CAVEAT: the knot is Q8_0, so 'scalar' IS the reference (err≡0).");
    println!("The lattice columns are the certified shift toward the lower-G value,");
    println!("NOT an error vs original f32 (that needs ~17GB HF DL + ~48GB f32 render");
    println!("which OOMs on a 16GB host — not attempted).");
}
